search:TypeScript and Testing Patterns f.content:
- Use `npm install --save-dev jest @testing-library/react @testing-library/jest-dom`
- Configure Jest in `jest.config.js`:
  ```javascript
  module.exports = {
    setupFilesAfterEnv: ['@testing-library/jest-dom/extend-expect'],
    testEnvironment: 'jsdom',
  };
  ```
- For Next.js 14 with App Router, use `npm install --save-dev @types/react @types/node`
- Example of a unit test for an API route:
  ```javascript
  import { rest } from 'msw';
  import { setupServer } from 'msw/node';

  const server = setupServer(
    rest.get('/api/items', (req, res, ctx) => {
      return res(ctx.json({ items: ['item1', 'item2'] }));
    })
  );

  beforeAll(() => server.listen());
  afterAll(() => server.close());
  afterEach(() => server.resetHandlers());

  test('fetches items correctly', async () => {
    const response = await fetch('/api/items');
    const data = await response.json();
    expect(data.items).toEqual(['item1', 'item2']);
  });
  ```
